import { evaluatePhase, PHASE_ORDER } from './.homeybuild/src/lib/engine/PhaseEngine.js';

console.log('=== Test 1: Transition should occur ===');
const mockConfig = {
  version: '1.0.0',
  roles: [],
  phases: {
    NIGHT: {
      weekday: { conditions: [{ type: 'time', at: '06:00' }] },
      weekend: { conditions: [{ type: 'time', at: '07:00' }] },
      states: {}
    },
    MORNING: {
      weekday: { conditions: [{ type: 'time', at: '09:00' }] },
      weekend: { conditions: [{ type: 'time', at: '10:00' }] },
      states: {}
    },
    DAY: {
      weekday: { conditions: [{ type: 'time', at: '18:00' }] },
      weekend: { conditions: [{ type: 'time', at: '19:00' }] },
      states: {}
    },
    EVENING: {
      weekday: { conditions: [{ type: 'time', at: '22:00' }] },
      weekend: { conditions: [{ type: 'time', at: '23:00' }] },
      states: {}
    }
  }
};

// Test with window that includes 09:00 (MORNING trigger)
const ctx1 = {
  now: new Date('2024-01-15T10:00:00'), // Monday 10am
  lux: null,
  latitude: 52.0,
  longitude: 5.0,
  countryCode: 'NL'
};

const result1 = evaluatePhase('NIGHT', new Date('2024-01-15T05:00:00'), mockConfig, ctx1);
console.log('Phase:', result1.phase);
console.log('Transitions:', JSON.stringify(result1.transitions, null, 2));
console.log('✓ Should transition NIGHT→MORNING at 09:00:', result1.transitions.length === 1 && result1.phase === 'MORNING');

console.log('\\n=== Test 2: Multiple transitions (fast-forward) ===');
const ctx2 = {
  now: new Date('2024-01-15T20:00:00'), // Monday 8pm
  lux: null,
  latitude: 52.0,
  longitude: 5.0,
  countryCode: 'NL'
};

const result2 = evaluatePhase('NIGHT', new Date('2024-01-15T05:00:00'), mockConfig, ctx2);
console.log('Phase:', result2.phase);
console.log('Transitions count:', result2.transitions.length);
console.log('Transitions:', JSON.stringify(result2.transitions.map(t => ({ from: t.from, to: t.to, reason: t.reason, eventTime: t.eventTime.toISOString() })), null, 2));
console.log('✓ Should have 3 transitions (NIGHT→MORNING→DAY→EVENING):', result2.transitions.length === 3 && result2.phase === 'EVENING');

console.log('\\n=== Test 3: Iteration cap ===');
const result3 = evaluatePhase('NIGHT', new Date('2024-01-15T00:00:00'), mockConfig, {
  now: new Date('2024-01-16T06:00:00'), // More than 4 transitions possible
  lux: null,
  latitude: 52.0,
  longitude: 5.0,
  countryCode: 'NL'
});
console.log('Phase:', result3.phase);
console.log('Transitions count:', result3.transitions.length);
console.log('cappedAt:', result3.cappedAt);
console.log('✓ Should be capped at 4:', result3.cappedAt === 4);
"

